//! Unified block building with tip-maximizing sort and sequencing rights.
//!
//! This module provides the refactored block building logic that:
//! 1. Collects all tip-paying transactions from multiple sources
//! 2. Sorts by effective tip (tip-maximizing)
//! 3. Applies sequencing rights bucketing
//! 4. Executes in unified order

pub enum AsyncCacheResult {
    ValidAsync,
    InvalidAsync,
    NotAsync,
}

pub struct CollectedTx<PoolTx: Clone + PoolTransaction> {
    pub bundle: TxBundle<PoolTx>,
    pub effective_tip: u128,
    pub estimated_gas: u64,
    pub original_index: usize,
}

pub fn new(bundle: TxBundle<PoolTx>, base_fee: u64, original_index: usize) -> Self {
    let effective_tip = bundle.effective_tip_per_gas(base_fee).unwrap_or(0);
    let estimated_gas = bundle.estimated_gas();
    Self { bundle, effective_tip, estimated_gas, original_index }
}

pub struct UnifiedCollection<PoolTx: Clone + PoolTransaction + std::fmt::Debug> {
    pub transactions: Vec<CollectedTx<PoolTx>>,
    pub scheduled_count: usize,
    pub fulfilled_count: usize,
    pub delivery_count: usize,
    pub regular_count: usize,
}

pub fn sort_by_tip(&mut self) {
    self.transactions.sort_by(|a, b| {
        b.effective_tip.cmp(&a.effective_tip).then(a.original_index.cmp(&b.original_index))
    });
}

pub fn estimate_tx_size(tx: &Recovered<TransactionSigned>) -> usize {
    tx.size() + 256
}

pub fn can_fit_in_block(tx_size: usize, current_size: usize, max_size: usize) -> bool {
    current_size + tx_size <= max_size
}

pub fn extract_delivery_effective_tip(input: &Bytes, base_fee: u64) -> u128 {
    if input.len() < 128 {
        return 0;
    }
    base_fee as u128
}

pub fn apply_sequencing_rights<PoolTx, SP, EvmConfig>(collection: &mut UnifiedCollection<PoolTx>, ... ) {
    if collection.is_empty() {
        return;
    }
    let ts_start = ritual_metrics::tx::current_timestamp_micros();

let state = match state_provider.state_by_block_hash(parent_header.hash_slow()) {
    Ok(s) => s,
    Err(e) => {
        tracing::warn!(target: "ritual::sequencing_rights", error = %e, "Failed to get state for sequencing rights, using original order");
        return;
    }
};

if let Some(classification) = try_classify_static(tx) {
    return (tx.clone(), classification);
}

if !use_full_call_graph {
    return (tx.clone(), classify_top_level_with_sr(tx, &reader, &state));
}

let mut inspector = ContractCallInspector::new();
let state_db = StateProviderDatabase::new(&state);
let db = State::builder().with_database(state_db).with_bundle_update().build();
let env = evm_config.evm_env(parent_header);
let mut evm = evm_config.evm_with_env_and_inspector(db, env, &mut inspector);
let result = evm.transact(tx.clone());
...
Err(e) => { ... (tx.clone(), Classification::NoSequencingRights) }

