let reordered = match reorder_block(classified_txs, parent_header, state_provider) {
    Ok(txs) => txs,
    Err(e) => {
        tracing::warn!(target: "ritual::sequencing_rights", error = %e, tx_count = collection.transactions.len(), "Sequencing rights reordering failed, using original order");
        return;
    }
};

if reordered.len() == collection.transactions.len() {
    let hash_to_new_pos: std::collections::HashMap<_, _> =
        reordered.iter().enumerate().map(|(pos, tx)| (*tx.tx_hash(), pos)).collect();
    collection.transactions.sort_by_key(|ct| {
        hash_to_new_pos.get(ct.bundle.primary_tx().tx_hash()).copied().unwrap_or(usize::MAX)
    });
}

let ts_end = ritual_metrics::tx::current_timestamp_micros();
ritual_metrics::block::log_payload_phase(
    "payload_sequencing_rights",
    block_number,
    ts_start,
    ts_end,
    collection.transactions.len(),
);

